#include<cstdio>
#include<bitset>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
const int N=1e5+10,W=1e5;std::bitset<N> S,I,ans;int blk;struct Nd{int l,r,idx,opt,x;}q[N];
int cnt[N],L,R,n,a[N],Q,lst[128][N],t[N],mx[128][N/128+100],loc[N],ql[N],qr[N];
inline void ins(int x){if(!(cnt[x]++))S[x]=true,I[W-x]=true;}
inline void del(int x){if(!(--cnt[x]))S[x]=false,I[W-x]=false;}
inline void Init(int x)
{
	memset(t,0,sizeof(t));rep(1,n,i)
	{
		if(a[i]*x<=W)lst[x][i]=t[a[i]*x];
		if(a[i]%x==0)lst[x][i]=max(lst[x][i],t[a[i]/x]);t[a[i]]=i;
		mx[x][loc[i]]=max(mx[x][loc[i]],lst[x][i]);
	}
}
inline bool qry(const int &l,const int &r,const int &x)
{
	if(x==1)return r>=l;
	int L=loc[l],R=loc[r];if(L==R){rep(l,r,i)if(lst[x][i]>=l)return true;return false;}
	rep(l,qr[L],i)if(lst[x][i]>=l)return true;rep(ql[R],r,i)if(lst[x][i]>=l)return true;
	rep(L+1,R-1,i)if(mx[x][i]>=l)return true;return false;
}
int main()
{
	n=read();Q=read();rep(1,n,i)a[i]=read(),loc[i]=(i-1)/128+1;
	blk=loc[n];rep(1,blk,i)ql[i]=qr[i-1]+1,qr[i]=i*128;qr[blk]=n;rep(2,127,i)Init(i);
	rep(1,Q,i)q[i].opt=read(),q[i].l=read(),q[i].r=read(),q[i].x=read(),q[i].idx=i;
	std::sort(q+1,q+Q+1,[&](const Nd&x,const Nd&y){return (x.l>>8)==(y.l>>8)?((x.l>>8)&1?x.r>y.r:x.r<y.r):x.l<y.l;});
	L=q[1].l;R=L-1;rep(1,Q,i)
	{
		if(q[i].opt==4&&q[i].x<128){ans[q[i].idx]=qry(q[i].l,q[i].r,q[i].x);continue;}
		while(R<q[i].r)ins(a[++R]);while(L>q[i].l)ins(a[--L]);while(R>q[i].r)del(a[R--]);while(L<q[i].l)del(a[L++]);
		switch(q[i].opt)
		{
			case 1: ans[q[i].idx]=(S&(S<<q[i].x)).count(); break;
			case 2: ans[q[i].idx]=(S&(I>>(W-q[i].x))).count(); break;
			case 3: for(int j=1;j*j<=q[i].x;++j)if(q[i].x%j==0&&S[j]&&S[q[i].x/j]){ans[q[i].idx]=true;break;} break;
			case 4: for(int j=1;j*q[i].x<=W;++j)if(S[j]&&S[j*q[i].x]){ans[q[i].idx]=true;break;}
		}
	}
	rep(1,Q,i)puts(ans[i]?"yuno":"yumi");return 0;
}
